import{_ as a,a as t,b as n,c as d}from"./chunks/查询额度成功.BYPQR2qF.js";import{_ as o,o as r,c as i,a2 as l}from"./chunks/framework.DnrXFDHb.js";const v=JSON.parse('{"title":"Een WebDAV-kanaal toevoegen","description":"","frontmatter":{},"headers":[],"relativePath":"nl-NL/upload/webdav.md","filePath":"nl-NL/upload/webdav.md","lastUpdated":1781962217000}'),s={name:"nl-NL/upload/webdav.md"};function p(c,e,h,b,g,u){return r(),i("div",null,[...e[0]||(e[0]=[l('<h1 id="een-webdav-kanaal-toevoegen" tabindex="-1">Een WebDAV-kanaal toevoegen <a class="header-anchor" href="#een-webdav-kanaal-toevoegen" aria-label="Permalink to &quot;Een WebDAV-kanaal toevoegen&quot;">​</a></h1><h2 id="wanneer-dit-geschikt-is" tabindex="-1">Wanneer dit geschikt is <a class="header-anchor" href="#wanneer-dit-geschikt-is" aria-label="Permalink to &quot;Wanneer dit geschikt is&quot;">​</a></h2><p>Gebruik het WebDAV-kanaal wanneer:</p><ul><li>je een NAS, cloudschijf of opslagdienst hebt die een WebDAV-endpoint aanbiedt.</li><li>geuploade afbeeldingen in je eigen WebDAV-map moeten worden opgeslagen.</li><li>je inloggegevens in de D1-tabel <code>upload_channels</code> wilt bewaren in plaats van ze langdurig in de frontend bloot te stellen.</li></ul><h2 id="wat-je-vooraf-nodig-hebt" tabindex="-1">Wat je vooraf nodig hebt <a class="header-anchor" href="#wat-je-vooraf-nodig-hebt" aria-label="Permalink to &quot;Wat je vooraf nodig hebt&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Vereiste</th><th>Doel</th></tr></thead><tbody><tr><td>WebDAV Endpoint</td><td>Server-side WebDAV-URL, bijvoorbeeld <code>https://nas.example.com/dav</code>.</td></tr><tr><td>Gebruikersnaam</td><td>Voor aanmelden bij de WebDAV-dienst.</td></tr><tr><td>Wachtwoord</td><td>Voor aanmelden bij de WebDAV-dienst.</td></tr><tr><td>Authenticatiemodus</td><td>Standaard <code>Basic</code>. Gebruik <code>Digest</code> of automatische onderhandeling alleen als de server dat vereist.</td></tr><tr><td>Opslagmap</td><td>Map waarin bestanden worden opgeslagen. Standaard <code>imgbed</code>.</td></tr></tbody></table><h2 id="waar-je-het-toevoegt" tabindex="-1">Waar je het toevoegt <a class="header-anchor" href="#waar-je-het-toevoegt" aria-label="Permalink to &quot;Waar je het toevoegt&quot;">​</a></h2><ol><li>Open Systeeminstellingen.</li><li>Ga naar Uploadinstellingen.</li><li>Klik rechtsboven op Kanaal toevoegen.</li><li>Selecteer <code>WebDAV</code>.</li></ol><h2 id="veldreferentie" tabindex="-1">Veldreferentie <a class="header-anchor" href="#veldreferentie" aria-label="Permalink to &quot;Veldreferentie&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Veld</th><th>Functie</th><th>Verplicht</th></tr></thead><tbody><tr><td>Kanaalnaam</td><td>Een herkenbare naam, bijvoorbeeld <code>koofr</code> of <code>nas</code>.</td><td>Ja</td></tr><tr><td>Endpoint</td><td>Volledige WebDAV-endpoint, inclusief <code>https://</code>.</td><td>Ja</td></tr><tr><td>Gebruikersnaam</td><td>WebDAV-loginnaam.</td><td>Ja</td></tr><tr><td>Wachtwoord</td><td>WebDAV-wachtwoord.</td><td>Ja</td></tr><tr><td>Authenticatiemodus</td><td>Meestal <code>Basic</code>; gebruik <code>Digest</code> als de server digest-authenticatie vereist.</td><td>Ja</td></tr><tr><td>Opslagmap</td><td>Map waarin bestanden worden opgeslagen. Standaard <code>imgbed</code>.</td><td>Nee</td></tr></tbody></table><h2 id="voorbeeld-fie-nl-tab-digital" tabindex="-1">Voorbeeld: fie.nl.tab.digital <a class="header-anchor" href="#voorbeeld-fie-nl-tab-digital" aria-label="Permalink to &quot;Voorbeeld: fie.nl.tab.digital&quot;">​</a></h2><h3 id="_1-maak-een-app-wachtwoord" tabindex="-1">1. Maak een app-wachtwoord <a class="header-anchor" href="#_1-maak-een-app-wachtwoord" aria-label="Permalink to &quot;1. Maak een app-wachtwoord&quot;">​</a></h3><p>Open de beveiligingsinstellingen van je account, zoek app-wachtwoorden en maak een nieuw app-wachtwoord.</p><p><img src="'+a+'" alt="App-wachtwoord maken" loading="lazy"></p><p>Kopieer en bewaar het nieuwe app-wachtwoord direct na het aanmaken. Meestal wordt het maar één keer getoond.</p><p><img src="'+t+'" alt="Nieuw app-wachtwoord bewaren" loading="lazy"></p><h3 id="_2-vul-de-webdav-configuratie-in-imgbed-in" tabindex="-1">2. Vul de WebDAV-configuratie in ImgBed in <a class="header-anchor" href="#_2-vul-de-webdav-configuratie-in-imgbed-in" aria-label="Permalink to &quot;2. Vul de WebDAV-configuratie in ImgBed in&quot;">​</a></h3><p>Ga terug naar ImgBed en voeg een WebDAV-kanaal toe:</p><table tabindex="0"><thead><tr><th>UI-veld</th><th>Waarde</th></tr></thead><tbody><tr><td>Endpoint</td><td>De WebDAV-URL van <code>https://fie.nl.tab.digital/</code>.</td></tr><tr><td>Gebruikersnaam</td><td>Je WebDAV-gebruikersnaam.</td></tr><tr><td>Wachtwoord</td><td>Het app-wachtwoord dat je net hebt gemaakt.</td></tr><tr><td>Authenticatiemodus</td><td>Begin in de meeste gevallen met <code>Basic</code>.</td></tr><tr><td>Opslagmap</td><td>Standaard <code>imgbed</code>; je kunt ook een eigen map gebruiken.</td></tr></tbody></table><p><img src="'+n+'" alt="Configuratie invullen" loading="lazy"></p><h2 id="gedrag-bij-grote-bestanden" tabindex="-1">Gedrag bij grote bestanden <a class="header-anchor" href="#gedrag-bij-grote-bestanden" aria-label="Permalink to &quot;Gedrag bij grote bestanden&quot;">​</a></h2><p>Het WebDAV-kanaal gebruikt nu echte sessiegebaseerde chunk-upload.</p><p>Kleine bestanden worden als één volledig bestand geüpload. Bestanden groter dan 64 MiB worden automatisch in delen van ongeveer 10 MiB gesplitst en naar een externe chunkmap geüpload.</p><p>De WebDAV-dienst hoeft geen <code>partial update</code> of offset-gebaseerde schrijfacties te ondersteunen. ImgBed voegt de chunks op de externe server niet samen tot één groot bestand. In plaats daarvan bewaart ImgBed een chunkmanifest en leest het de chunks in volgorde wanneer het bestand wordt opgevraagd.</p><p>In de praktijk:</p><table tabindex="0"><thead><tr><th>Bestandsgrootte</th><th>Uploadmethode</th><th>Externe opslagstructuur</th></tr></thead><tbody><tr><td>64 MiB of kleiner</td><td>Normale upload</td><td>Eén volledig bestand</td></tr><tr><td>Groter dan 64 MiB</td><td>Echte sessiegebaseerde chunk-upload</td><td>Een chunkmap met meerdere deelbestanden</td></tr></tbody></table><p>De chunkmap beïnvloedt alleen de structuur in de externe opslag. De bestands-URL in ImgBed verandert niet. Gebruikers blijven het bestand openen via de oorspronkelijke <code>/file/...</code>-link.</p><h2 id="instelstappen" tabindex="-1">Instelstappen <a class="header-anchor" href="#instelstappen" aria-label="Permalink to &quot;Instelstappen&quot;">​</a></h2><ol><li>Open Uploadinstellingen.</li><li>Klik op Kanaal toevoegen.</li><li>Selecteer <code>WebDAV</code>.</li><li>Vul een herkenbare kanaalnaam in, bijvoorbeeld <code>koofr</code>.</li><li>Vul de WebDAV-endpoint in, bijvoorbeeld <code>https://app.koofr.net/dav/Koofr</code>.</li><li>Vul gebruikersnaam en wachtwoord in.</li><li>Laat authenticatiemodus standaard op <code>Basic</code>.</li><li>Laat de opslagmap op <code>imgbed</code>, of verander deze naar je eigen map.</li><li>Klik op Opslaan.</li><li>Controleer na opslaan de kanaalkaart, vraag capaciteit op als dat beschikbaar is en upload een testbestand.</li></ol><h2 id="controleren" tabindex="-1">Controleren <a class="header-anchor" href="#controleren" aria-label="Permalink to &quot;Controleren&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Controle</th><th>Hoe je controleert</th></tr></thead><tbody><tr><td>Kanaalkaart verschijnt</td><td>Na opslaan moet in Uploadinstellingen een WebDAV-kanaalkaart zichtbaar zijn.</td></tr><tr><td>Kanaal is actief</td><td>De schakelaar rechtsboven op de kaart blijft aan.</td></tr><tr><td>Inloggegevens zijn opgeslagen</td><td>De detailweergave toont Endpoint, gebruikersnaam, authenticatiemodus en opslagmap.</td></tr><tr><td>Klein bestand uploadt</td><td>Upload een testafbeelding en controleer of die in de WebDAV-map verschijnt.</td></tr><tr><td>Regel voor grote bestanden werkt</td><td>Bestanden groter dan 64 MiB gebruiken chunk-upload en maken een externe chunkmap.</td></tr><tr><td>Capaciteitsopvraag werkt</td><td>Als de server capaciteitsinformatie ondersteunt, worden gebruikt en totaal weergegeven.</td></tr></tbody></table><p><img src="'+d+`" alt="Quota-opvraag gelukt" loading="lazy"></p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="waarom-maken-grote-webdav-bestanden-een-chunkmap" tabindex="-1">Waarom maken grote WebDAV-bestanden een chunkmap? <a class="header-anchor" href="#waarom-maken-grote-webdav-bestanden-een-chunkmap" aria-label="Permalink to &quot;Waarom maken grote WebDAV-bestanden een chunkmap?&quot;">​</a></h3><p>Dit is de huidige opslagmethode voor grote bestanden.</p><p>Bestanden groter dan 64 MiB worden niet samengevoegd tot één groot extern bestand. Ze worden opgeslagen als chunkmap. ImgBed bewaart het chunkmanifest en levert de volledige inhoud door de delen in volgorde te lezen.</p><h3 id="wat-controleer-ik-eerst-als-upload-van-grote-bestanden-mislukt" tabindex="-1">Wat controleer ik eerst als upload van grote bestanden mislukt? <a class="header-anchor" href="#wat-controleer-ik-eerst-als-upload-van-grote-bestanden-mislukt" aria-label="Permalink to &quot;Wat controleer ik eerst als upload van grote bestanden mislukt?&quot;">​</a></h3><p>Controleer eerst Endpoint, gebruikersnaam, wachtwoord en opslagmap. Controleer daarna of de WebDAV-dienst mappen mag maken, bestanden mag schrijven en bestanden mag lezen.</p><p>Als de capaciteitsopvraag mislukt maar kleine uploads werken, ondersteunt de server mogelijk geen capaciteitsrapportage of beperkt hij deze. Dat betekent niet automatisch dat uploaden niet beschikbaar is.</p><h3 id="welke-authenticatiemodus-moet-ik-kiezen" tabindex="-1">Welke authenticatiemodus moet ik kiezen? <a class="header-anchor" href="#welke-authenticatiemodus-moet-ik-kiezen" aria-label="Permalink to &quot;Welke authenticatiemodus moet ik kiezen?&quot;">​</a></h3><p>Begin met <code>Basic</code>.</p><p>Als de server expliciet digest-authenticatie vereist, gebruik dan <code>Digest</code>.</p><p>Als je het niet zeker weet, gebruik automatische onderhandeling.</p><h2 id="snelle-checklist" tabindex="-1">Snelle checklist <a class="header-anchor" href="#snelle-checklist" aria-label="Permalink to &quot;Snelle checklist&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Bereid WebDAV-endpoint, gebruikersnaam en wachtwoord voor</span></span>
<span class="line"><span>-&gt; Open Uploadinstellingen</span></span>
<span class="line"><span>-&gt; Kanaal toevoegen</span></span>
<span class="line"><span>-&gt; Selecteer WebDAV</span></span>
<span class="line"><span>-&gt; Vul Endpoint / gebruikersnaam / wachtwoord in</span></span>
<span class="line"><span>-&gt; Laat authenticatiemodus standaard op Basic</span></span>
<span class="line"><span>-&gt; Laat opslagmap standaard op imgbed</span></span>
<span class="line"><span>-&gt; Sla op</span></span>
<span class="line"><span>-&gt; Vraag capaciteit op</span></span>
<span class="line"><span>-&gt; Upload een testbestand</span></span></code></pre></div>`,45)])])}const w=o(s,[["render",p]]);export{v as __pageData,w as default};
